var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"역시 나이엘이야! 인정사정 없이 몰아붙이고 있어!","JPN":"さすがナイエル！　容赦なく追い込んでる！","ENG":"That's so like Naielle. Look at the way she's pushing her!","TWN":"不愧是奈爾！出手毫不留情呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"굉장해! 상대가 초등부 학생이라도 자비가 없지!","JPN":"すごい！　相手が初等部でも容赦しない！","ENG":"Incredible! She shows mercy to no one—not even an elementary school kid!","TWN":"太厲害了！哪怕對手是小學部的學生也毫不手軟！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으으......","JPN":"うう……","ENG":"Ugh...","TWN":"嗚嗚……"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"호오, 꽤 하는걸? 하지만 얼마나 버틸 수 있을까?","JPN":"へえ、やるじゃない！　でもいつまで耐えられるのかしら？","ENG":"Ooo, you're pretty good. Let's see how long you last.","TWN":"呼噢，有兩下子？我倒要看看你能撐多長時間？"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"뭐야, 이 꼬맹이! 보기보다 힘이 엄청 세잖아?!","JPN":"なんだこのチビ！　見た目よりすごい力持ちじゃん！？","ENG":"Geez, this kid! She's much stronger than she looks!","TWN":"哎呦，這個小不點！力氣比看起來大很多啊？！"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"말도 안 돼! 초등부에 이런 녀석이 있다는 얘기 들은 적 없는데?!","JPN":"ありえない！　初等部にこんな子がいるなんて話は聞いてない！！","ENG":"This doesn't make sense! I've never heard of anyone so strong in elementary school.","TWN":"不可能！我沒聽說小學部有這種傢伙啊？！"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"괜히 힘 대결로 들어갔어! 이럴 줄 알았으면 처음부터 그냥 기술로 몰아붙이는 건데!","JPN":"力勝負にするべきじゃなかった！　最初から技で追い詰めればよかったわ！","ENG":"Why did I decide to use physical strength against her? I should have pressured her with my skills to begin with!","TWN":"用力量對決沒什麼用了！早知道一開始我就應該直接靠技能碾壓！"},"stage":{"bg":"BLACK","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"읏......!","JPN":"うっ……！","ENG":"Ngh!","TWN":"呃……！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"팔이 떨려...... 역시 그만둘래......","JPN":"腕が震える……やっぱりやめる……","ENG":"My hands are shaking... I'm just going to give up...","TWN":"手臂抖的很厲害……不行，我要放棄……"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"자! 이대로 얌전히 떨어지라고!","JPN":"さあ！　これで大人しく落ちなさい！","ENG":"Now, be a good girl and get out of the ring!","TWN":"好！就這樣安靜地掉下去吧！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......케이시! 힘내!!","JPN":"……ケイシー！　頑張って！！","ENG":"... Kaci! Bear up!","TWN":"……卡西！加油！！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"앗......!","JPN":"あっ……！","ENG":"Ah!","TWN":"啊……！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"어...... 얼레? 내가 구석에 몰렸는데?","JPN":"あ……あれ？　私が端っこに！？","ENG":"Err? What happened? How did I get myself cornered?","TWN":"哎……哎呦？我被逼到角落裡了？"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"궁지에 몰렸던 청팀 선수! 순식간에 홍팀 선수 뒤로 파고들어 밀어냅니다!","JPN":"窮地に追い込まれていた青組選手！　あっという間に赤組選手の後ろに突っ込んで押し出します！","ENG":"The Blue Team player escapes from danger and quickly goes behind her opponent, pushing her!","TWN":"被逼入絕境的藍隊選手！一瞬間跑到了紅隊選手背後，將紅隊選手推了下去！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"나이엘 선수, 안타깝게도 장외 실격이네요!","JPN":"ナイエル選手、残念ながら場外になり失格です！","ENG":"Naielle is out of the ring! She's been disqualified!","TWN":"很遺憾，奈爾選手掉到了場外失去了資格！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......이겼어. 나......","JPN":"勝てた……あたしが……","ENG":"I... won...","TWN":"……我贏了，我……"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......아앗.","JPN":"……ああっ。","ENG":"... Ah!","TWN":"……啊啊。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"저어...... 죄송해요. 다치진 않으셨나요?","JPN":"あの……すみません、お怪我はありませんか？","ENG":"Erm... I'm sorry. Are you hurt anywhere?","TWN":"那個……對不起，你沒受傷吧？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"바, 방금 뭐가 어떻게 돌아간 거야?","JPN":"い、今のは何がどうなったの？","ENG":"W-what just happened?","TWN":"剛，剛剛是怎麼回事？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"졌다고? 이 내가...... 초등부한테?","JPN":"負けた？　この私が……初等部に？","ENG":"I lost to an elementary school kid?","TWN":"輸了？我……輸給小學部的人？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"펴, 편입생?","JPN":"へ、編入生？","ENG":"T-transfer student?","TWN":"插，插班生？"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......승리를 예고했던 후배에게 패배 당한다.","JPN":"……勝利を予告した後輩に負ける。","ENG":"... You were beaten by the junior whom you underestimated.","TWN":"……輸給預告勝利的後輩。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"아카데미 학생으로선 최고의 굴욕이네.","JPN":"アカデミー生徒として最大の屈辱だわ。","ENG":"This must be the greatest humiliation for an Academy student.","TWN":"是身為學院學生最大的恥辱。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"앗, 아앗......","JPN":"あ、ああっ……","ENG":"Ah, aaah...","TWN":"啊，啊啊……"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그럼 힘내, 아카데미 최강. 난 경기가 있어서.","JPN":"それじゃあ、頑張ってねアカデミー最強さん。私は試合があるので。","ENG":"Buck up, Academy's best. I've got a game to play.","TWN":"那妳加油吧，學院最強。我還有比賽。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"풉.","JPN":"プッ。","ENG":"Poof.","TWN":"噗。"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"너......! 너어......!","JPN":"あんた……！　よくも……！","ENG":"You... Youuu!","TWN":"妳……！妳……！"},"stage":{"bg":"SPORTSGROUND","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"너어어어어어어어어어!!","JPN":"許さなあああああああい！！","ENG":"YOUUUUUU!","TWN":"妳妳妳妳妳妳妳妳妳！！"},"stage":{"bg":"SS_SPORTS_02","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗...... 이런 게 아이들의 우정이란 거려나.","JPN":"フフッ、これが子どもたちの友情ってことかしら。","ENG":"Hah hah. So this is how kids get close to each other.","TWN":"呵呵……這些應該就是孩子們的友情吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"생각보다 더 재미있네.","JPN":"思ったより面白いわね。","ENG":"It's more fun than I thought.","TWN":"比我想得更有趣呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"너도 그렇게 생각하지 않니, 얘?","JPN":"あなたもそう思わない？","ENG":"Don't you agree, girl?","TWN":"你也那麼認為嗎，孩子？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"제가...... 보이세요?","JPN":"私が……見えるの？","ENG":"Can you... see me?","TWN":"您……能看見我？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"아니, 나도 잘 보이진 않아.","JPN":"ううん、私もちゃんとした姿は見えないの。","ENG":"No, not clearly.","TWN":"不，我也看不太清楚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"아마도 넌 존재감이 많이 희박해지는 힘을 가진 것 같네.","JPN":"おそらくあなたは存在感が薄れるような力を持っているようね。","ENG":"It looks like you have the power to blur your existence.","TWN":"你好像有一種存在感很稀薄的力量。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"하지만 예전부터 몰래 숨어 있는 녀석들을 찾아내는 게 내 특기였거든.","JPN":"でも、昔からこっそり隠れている子を見つけ出すのが私の特技だったの。","ENG":"But I was really good at finding people who were concealing themselves.","TWN":"不過從很久以前開始，我就很擅長找出隱藏的傢伙。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"훈련 받기 싫어서 기지 뒤편에 몰래 숨어있는 예고르라던가......","JPN":"訓練をサボりたくて基地の裏側に隠れていたイェゴールとか……","ENG":"Like Yegor, who used to hide behind the base to avoid training...","TWN":"比如不想接受訓練，偷偷躲在基地後面的伊高爾……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"류드밀라가 저기압일 때마다 화장실 어딘가로 사라지던 발레리라던가......","JPN":"リュドミラがイライラしているたびにトイレのどこかに隠れてしまうヴァレリーとか……","ENG":"Or Valeriy, who disappeared into the bathroom whenever Lyudmila was upset...","TWN":"每當盧德米拉心情不好時，都會躲在某些地方，比如說廁所裡……之類的"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그런 녀석들을 귀신같이 찾아서 내무반으로 끌고 오는 게 내 일이었지.","JPN":"あの子たちを見つけて宿舎に連れ戻すのが私の仕事だったのよ。","ENG":"It was my daily routine to find and drag them back to the barracks.","TWN":"把她們找出來並帶回宿舍就是我的工作。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"무슨 말씀인지...... 모르겠어요.","JPN":"なんの話なのか……わからない。","ENG":"I... don't know what you're talking about.","TWN":"我聽不懂……您在說什麼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"지금은 몰라도 된단다.","JPN":"今はわからなくていいの。","ENG":"You don't have to know. For now.","TWN":"現在不知道也沒關係。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"언젠가 네게도 동료라고 부를 수 있는 사람들이 생기면 알게 될 거야.","JPN":"いつかあなたに仲間と呼べる人ができたら、きっとわかるわ。","ENG":"You'll know one day if you find people whom you can call teammates.","TWN":"等有一天你也有了可以稱之為同伴的朋友時，自然就知道了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그러니 여긴 내게 맡기고 친구들에게 돌아가렴.","JPN":"だからここは私に任せてお友達のところに戻りなさい。","ENG":"So, leave this place to me and go back to your friends.","TWN":"所以這裡交給我，去找你的朋友們吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......알고 계셨어요?","JPN":"……知っていたの？","ENG":"... Did you know?","TWN":"……您知道？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그럼.","JPN":"ええ。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"소원구슬의 힘에 이끌려 침식체들이 나타난 거잖니.","JPN":"願い玉の力に惹かれて侵食体が現れたのでしょう。","ENG":"The power of the Wishing Ball has attracted those C.O.s.","TWN":"許願珠力量引來了很多侵蝕體。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"이대로 두면 소중한 친구들의 운동회가 엉망이 될까 봐 온 거지?","JPN":"放っておくと、大切な友達の運動会が中止になってしまうかもしれないから来たのよね？","ENG":"You came because you didn't want them to ruin your friends' Field Day, right?","TWN":"你擔心它們會破壞你重視的朋友一直期待的運動會才來的對吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"어른들을 부르려고 해도 네 말을 들어주는 사람이 없으니까.","JPN":"助けてくれる大人を呼びたくても、あなたの話を聞いてくれる人はいないから。","ENG":"You couldn't talk to any grown-ups because they couldn't hear you.","TWN":"你想叫大人們過來，可是沒有人聽你的話。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"하지만 네 말을 듣고 있는 사람이 여기 한 명은 있단다.","JPN":"でも、あなたの話が聞ける人がここに一人いるわ。","ENG":"But there's one to hear you here.","TWN":"不過這裡有一個聽你說話的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"나도 마침 선수 보호자로 온 거라서 말이야.","JPN":"私もちょうどタイミングよく、選手の保護者としてここに来ていたの。","ENG":"And I'm here as a chaperone for one of the players.","TWN":"我是這些選手的監護人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"운동회를 망치는 녀석들은 혼을 내줄 생각이거든.","JPN":"運動会を邪魔する子は叱ってあげないと。","ENG":"It's my job to stop anyone from ruining the Field Day.","TWN":"我也想教訓一下破壞運動會的傢伙。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"고마워요......","JPN":"……ありがとう。","ENG":"Thank you...","TWN":"謝謝您……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"그럼...... 부탁드릴게요.","JPN":"じゃあ……お願いするね。","ENG":"Then... I'll count on you.","TWN":"那……就拜託您了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"맡겨두렴.","JPN":"任せてちょうだい。","ENG":"Don't worry.","TWN":"交給我吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};